 using System.ComponentModel;
 using System.Text.Json;
 using Microsoft.Extensions.AI;
 using OpenAI;

 // ─── Configuration ───────────────────────────────────────────────────────────

 var modelName = Environment.GetEnvironmentVariable("OPENAI_MODEL") ?? "gpt-4o-mini";
 var apiKey = Environment.GetEnvironmentVariable("OPENAI_API_KEY")
     ?? throw new InvalidOperationException(
         "Set the OPENAI_API_KEY environment variable before running.");

 var topic = args.Length > 0
     ? string.Join(' ', args)
     : PromptForTopic();

 Console.WriteLine($"\n🔍  Researching: {topic}\n");

 // ─── Build AI client with automatic tool invocation ──────────────────────────

 IChatClient chatClient = new OpenAIClient(apiKey)
     .GetChatClient(modelName)
     .AsIChatClient()
     .AsBuilder()
     .UseFunctionInvocation()
     .Build();

 // ─── Register tools ──────────────────────────────────────────────────────────

 var notebook = new Notebook();
 var searcher = new WebSearcher();

 var tools = new AITool[]
 {
     AIFunctionFactory.Create(searcher.SearchWeb),
     AIFunctionFactory.Create(searcher.FetchPage),
     AIFunctionFactory.Create(notebook.TakeNote),
     AIFunctionFactory.Create(notebook.ReadNotes),
 };

 // ─── System prompt ───────────────────────────────────────────────────────────

 const string systemPrompt = """
     You are a research agent. Your job is to research the given topic thoroughly.

     Follow this process:
     1. Search the web for information about the topic using several varied queries.
     2. When a search result looks promising, fetch the full page for deeper reading.
     3. Take notes on every key finding — include facts, dates, and sources.
     4. After gathering enough material, read your notes to review them.
     5. Produce a comprehensive, well-structured summary citing your sources.

     Guidelines:
     - Make at least 3 different searches with varied angles on the topic.
     - Always take notes before moving on to the next search.
     - Your final answer must be a polished summary, not raw notes.
     """;

 // ─── Agent loop ──────────────────────────────────────────────────────────────

 var messages = new List<ChatMessage>
 {
     new(ChatRole.System, systemPrompt),
     new(ChatRole.User, $"Please research the following topic: {topic}"),
 };

 var options = new ChatOptions { Tools = [.. tools] };

 Console.WriteLine("Agent is working…\n");

 var response = await chatClient.GetResponseAsync(messages, options);

 // ─── Output ──────────────────────────────────────────────────────────────────

 Console.WriteLine("\n═══════════════════════════════════════");
 Console.WriteLine("           RESEARCH SUMMARY            ");
 Console.WriteLine("═══════════════════════════════════════\n");
 Console.WriteLine(response.Text);

 if (notebook.Notes.Count > 0)
 {
     Console.WriteLine("\n───────────────────────────────────────");
     Console.WriteLine("           COLLECTED NOTES             ");
     Console.WriteLine("───────────────────────────────────────\n");
     foreach (var (title, content) in notebook.Notes)
         Console.WriteLine($"📌 {title}\n   {content}\n");
 }

 return;

