 /// <summary>Web search and page-fetching tool backed by DuckDuckGo.</summary>
 public sealed class WebSearcher
 {
     private static readonly HttpClient Http = new()
     {
         Timeout = TimeSpan.FromSeconds(15),
         DefaultRequestHeaders =
         {
             { "User-Agent", "ResearchAgent/1.0 (compatible)" },
             { "Accept", "text/html,application/xhtml+xml,application/json" },
         },
     };

     [Description("Search the web for information. Returns a list of results with titles, snippets, and URLs.")]
     public async Task<string> SearchWeb(
         [Description("The search query string")] string query)
     {
         Console.WriteLine($"  🌐 Searching: \"{query}\"");

         try
         {
             var encoded = Uri.EscapeDataString(query);
             var url = $"https://api.duckduckgo.com/?q={encoded}&format=json&no_html=1&skip_disambig=1";
             var json = await Http.GetStringAsync(url);

             using var doc = JsonDocument.Parse(json);
             var root = doc.RootElement;
             var results = new List<string>();

             AppendIfPresent(root, "Abstract", "AbstractSource", "AbstractURL", results);

             if (root.TryGetProperty("RelatedTopics", out var topics))
                 CollectTopics(topics, results, depth: 0);

             var answer = root.GetProperty("Answer").GetString();
             if (!string.IsNullOrWhiteSpace(answer))
                 results.Add($"Direct answer: {answer}");

             return results.Count > 0
                 ? string.Join("\n\n", results)
                 : $"No results found for \"{query}\". Try rephrasing or broadening the query.";
         }
         catch (Exception ex)
         {
             return $"Search error: {ex.Message}";
         }
     }

     [Description("Fetch the text content of a web page given its URL. Use this to get detailed information from a search result.")]
     public async Task<string> FetchPage(
         [Description("The full URL to fetch")] string url)
     {
         Console.WriteLine($"  📄 Fetching: {url}");

         try
         {
             var html = await Http.GetStringAsync(url);

             // Crude but effective: strip tags, collapse whitespace, and truncate.
             var text = StripHtml(html);
             const int maxLen = 6_000;
             if (text.Length > maxLen)
                 text = text[..maxLen] + "\n\n[… content truncated]";

             return string.IsNullOrWhiteSpace(text)
                 ? "Page returned no readable text content."
                 : text;
         }
         catch (Exception ex)
         {
             return $"Failed to fetch page: {ex.Message}";
         }
     }

     // ── Private helpers ──────────────────────────────────────────────────────

     private static void AppendIfPresent(
         JsonElement root, string textProp, string sourceProp, string urlProp,
         List<string> results)
     {
         var text = root.GetProperty(textProp).GetString();
         if (string.IsNullOrWhiteSpace(text)) return;

         var source = root.GetProperty(sourceProp).GetString();
         var link = root.GetProperty(urlProp).GetString();
         results.Add($"Summary ({source}): {text}\nSource: {link}");
     }

     private static void CollectTopics(JsonElement topics, List<string> results, int depth)
     {
         if (depth > 1) return;

         foreach (var item in topics.EnumerateArray())
         {
             if (item.TryGetProperty("Text", out var text) &&
                 !string.IsNullOrWhiteSpace(text.GetString()))
             {
                 var link = item.TryGetProperty("FirstURL", out var u) ? u.GetString() : "";
                 results.Add($"• {text.GetString()}\n  URL: {link}");
             }

             if (item.TryGetProperty("Topics", out var sub))
                 CollectTopics(sub, results, depth + 1);
         }
     }

     private static string StripHtml(string html)
     {
         // Remove script/style blocks, then all tags, then collapse whitespace.
         var noScript = System.Text.RegularExpressions.Regex.Replace(
             html, @"<(script|style)[^>]*>[\s\S]*?</\1>", " ",
             System.Text.RegularExpressions.RegexOptions.IgnoreCase);

         var noTags = System.Text.RegularExpressions.Regex.Replace(noScript, @"<[^>]+>", " ");
         var decoded = System.Net.WebUtility.HtmlDecode(noTags);
         return System.Text.RegularExpressions.Regex.Replace(decoded, @"\s+", " ").Trim();
     }
